sql:
SELECT theme_name 
FROM themes 
WHERE created_by = 0;

SELECT themes.theme_name, colors.color_name
FROM themes
JOIN colors ON themes.theme_id = colors.theme_id;

SELECT COUNT(*)
FROM themes
WHERE is_active = 1;

SELECT DISTINCT T2.user_name, T2.department
FROM themes AS T1
INNER JOIN users AS T2 ON T1.created_by = T2.user_id;

external_knowledge:
- "shining stars" refers to users who are very active;
- "most vocal in leaving comments" indicates users who have made the maximum number of comments;
- "showered us with the greatest number of contributions" refers to users who have made the maximum number of contributions;
- "over the past two lunar cycles" is a metaphorical way of saying "in the last two months".

sql:
SELECT created_by, COUNT(theme_id) AS number_of_themes
FROM themes
GROUP BY created_by;

SELECT themes.theme_name, borders.border_name
FROM themes
JOIN borders ON themes.theme_id = borders.theme_id;

SELECT theme_name, theme_description, is_active
FROM themes
WHERE created_by = 1;

external_knowledge:
- 'sprouted from the minds' refers to the themes being created; 
- 'till the digital soil as developers' refers to users having the role 'developer';
- 'architects' refers to the users who created the themes;
- 'typefaces they chose from the Arial font family' refers to the font family 'Arial' used in the text styles;
- 'the very first theme' refers to the theme with `theme_id` 1;
- 'descending alphabetical bouquet' means ordering by theme name in descending order.

sql:
SELECT project_id 
FROM themes 
WHERE theme_name = 'Default Theme' AND theme_id < 5;

SELECT theme_id, COUNT(*)
FROM theme_versions
GROUP BY theme_id;

SELECT u.user_name, u.email, tc.comment_text
FROM users u
JOIN theme_comments tc ON u.user_id = tc.user_id;
